from vex_sdk import VexClient
from openai import OpenAI

vex = VexClient(api_key="your-vex-key")
openai_client = OpenAI()

@webhook_handler('/verify-run')
def verify_openai_run(event):
    thread_id = event['data']['thread_id']
    run_id = event['data']['id']

    run = openai_client.beta.threads.runs.retrieve(thread_id, run_id)
    messages = openai_client.beta.threads.messages.list(thread_id)

    # Extract tool calls for verification
    tool_calls = []
    for msg in messages.data:
        if hasattr(msg, 'tool_calls'):
            tool_calls.extend(msg.tool_calls)

    # Vex verification
    result = vex.verify(
        task='workflow_step_validation',
        inputs={
            'tool_calls': [tc.function.call for tc in tool_calls],
            'thread_context': len(messages.data)
        },
        checks=[
            'action_correctness',
            'permission_validation',
            'idempotency_check'
        ]
    )

    if not result.passed:
        # Trigger rollback
        rollback_workflow(thread_id, run_id)

    return {'status': 'verified', 'passed': result.passed}

import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export async function validateToolCalls(toolCalls: any[]) {
  const results = await Promise.all(
    toolCalls.map(async (call) => {
      const verification = await vex.verify({
        task: 'function_schema_validation',
        inputs: {
          function_name: call.function.name,
          arguments: JSON.parse(call.function.arguments),
          schema: getFunctionSchema(call.function.name)
        },
        checks: ['json_schema_compliance', 'parameter_bounds']
      });

      return {
        callId: call.id,
        valid: verification.passed,
        errors: verification.failures
      };
    })
  );

  return results.filter(r => !r.valid);
}

async function handleIdempotencyCheck(threadId: string, toolCalls: any[]) {
  const vexCheck = await vex.verify({
    task: 'workflow_idempotency',
    inputs: {
      thread_id: threadId,
      operations: toolCalls.map(tc => ({
        name: tc.function.name,
        args: JSON.parse(tc.function.arguments),
        timestamp: new Date().toISOString()
      }))
    },
    checks: ['duplicate_operations', 'state_consistency']
  });

  if (!vexCheck.passed) {
    // Rollback last N steps
    await rollbackThreadSteps(threadId, vexCheck.context.step_count);

    // Notify human-in-loop
    await sendApprovalRequest({
      threadId,
      reason: 'Idempotency failure detected',
      rollback: true
    });
  }
}
